// Minimal JS mode for Ace (small subset)
/* global ace */
ace.define('ace/mode/javascript_highlight_rules', ['require', 'exports', 'module', 'ace/lib/oop', 'ace/mode/text_highlight_rules'], function (require, exports, module) {
  const oop = require('ace/lib/oop');
  const TextHighlightRules = require('ace/mode/text_highlight_rules').TextHighlightRules;

  const JsHighlightRules = function () {
    const keywords = (
      'break|case|catch|class|const|continue|debugger|default|delete|do|else|export|extends|finally|for|function|if|' +
      'import|in|instanceof|let|new|return|super|switch|this|throw|try|typeof|var|void|while|with|yield|await|async'
    );
    const keywordMapper = this.createKeywordMapper(
      { 'keyword.control': keywords, 'constant.language': 'true|false|null|undefined' },
      'identifier'
    );

    this.$rules = {
      start: [
        { token: 'comment', regex: '\\/\\/.*$' },
        { token: 'comment', start: '\\/\\*', end: '\\*\\/' },
        { token: 'string', regex: "'(?:\\\\.|[^'\\\\])*'" },
        { token: 'string', regex: '"(?:\\\\.|[^"\\\\])*"' },
        { token: 'string', regex: '`(?:\\\\.|[^`\\\\])*`' },
        { token: 'constant.numeric', regex: '\\b\\d+(?:\\.\\d+)?\\b' },
        { token: keywordMapper, regex: '[a-zA-Z_$][a-zA-Z0-9_$]*\\b' },
        { token: 'paren.lparen', regex: '[\\[\\(\\{]' },
        { token: 'paren.rparen', regex: '[\\]\\)\\}]' },
        { token: 'text', regex: '\\s+' },
      ],
    };
  };
  oop.inherits(JsHighlightRules, TextHighlightRules);
  exports.JavaScriptHighlightRules = JsHighlightRules;
});

ace.define('ace/mode/javascript', ['require', 'exports', 'module', 'ace/lib/oop', 'ace/mode/text', 'ace/mode/javascript_highlight_rules'], function (require, exports, module) {
  const oop = require('ace/lib/oop');
  const TextMode = require('ace/mode/text').Mode;
  const Rules = require('ace/mode/javascript_highlight_rules').JavaScriptHighlightRules;

  const Mode = function () {
    this.HighlightRules = Rules;
    this.$behaviour = this.$defaultBehaviour;
  };
  oop.inherits(Mode, TextMode);

  (function () {
    this.lineCommentStart = '//';
    this.blockComment = { start: '/*', end: '*/' };
  }).call(Mode.prototype);

  exports.Mode = Mode;
});

